def isvar(expr):
    return isinstance(expr, str) and expr.startswith("?")

def rename_variables(expr, n):
    if isvar(expr):
        return expr + "_" + str(n)
    elif isinstance(expr, list):
        return [rename_variables(part, n) for part in expr]
    else:
        return expr

rule = [["ancestor", "?a", "?y"],
        ["parent", "?a", "?z"],
        ["ancestor", "?z", "?y"]]

renamed_rule = rename_variables(rule, 7)
print(renamed_rule)
